/* ✨ 2. [보조 엔진] 해당 모델이 패키지 대상(구독)인지 판별 (서픽스 무시 및 스타일러 예외 처리) */
function isLifestyleTarget(rawLine) {
    if (!rawLine || rawLine === '-') return false;
    
    // 점(.) 앞부분 핵심 모델명 추출
    const baseLineCode = rawLine.toUpperCase().split('.')[0].replace(/\s+/g, '').replace(/\[구독\]/g, '');
    if (!baseLineCode) return false;
    
    for (let i = 0; i < LIFESTYLE_MODELS.length; i++) {
        const masterBaseCode = LIFESTYLE_MODELS[i].code.toUpperCase().split('.')[0];
        if (baseLineCode.includes(masterBaseCode) || masterBaseCode.includes(baseLineCode)) return true;
        
        // 스타일러 S3/SC3 호환 인식
        if (masterBaseCode.startsWith('SC') && baseLineCode.startsWith('S')) {
            const modMaster = masterBaseCode.replace(/^SC/, 'S');
            if (baseLineCode.includes(modMaster) || modMaster.includes(baseLineCode)) return true;
        }
    }
    return false;
}

/* ✨ 3. [메인 엔진] 선택된 모델들을 분석하여 뱃지 HTML을 반환 (줄바꿈 오류 방어 포함) */
function analyzeLifestyleOption(modelText) {
    try {
        if (!modelText || modelText === '-') {
            return { html: '<span style="color:#999; font-size:12px;">선택 가전 없음</span>' };
        }
        
        const rawLines = String(modelText).split('\n').map(m => m.trim()).filter(Boolean);
        const mergedLines = [];
        
        // 줄바꿈으로 분리된 [구독] 텍스트 윗줄 병합
        for (const line of rawLines) {
            if (line.includes('[구독]') && line.replace(/\[구독\]/g, '').trim() === '') {
                if (mergedLines.length > 0) mergedLines[mergedLines.length - 1] += ' [구독]';
            } else {
                mergedLines.push(line);
            }
        }

        const ownedCategories = new Set();
        
        mergedLines.forEach(line => {
            if (!line.includes('[구독]')) return; 
            
            let checkStr = line.toUpperCase().split('.')[0].replace(/\s+/g, '').replace(/\[구독\]/g, '');
            
            for (const item of LIFESTYLE_MODELS) {
                const masterBaseCode = item.code.toUpperCase().split('.')[0];
                let isMatch = false;
                
                if (checkStr.includes(masterBaseCode) || masterBaseCode.includes(checkStr)) {
                    isMatch = true;
                } else if (masterBaseCode.startsWith('SC') && checkStr.startsWith('S')) {
                    const modMaster = masterBaseCode.replace(/^SC/, 'S');
                    if (checkStr.includes(modMaster) || modMaster.includes(checkStr)) isMatch = true;
                }
                
                if (isMatch) {
                    ownedCategories.add(item.category);
                    break; 
                }
            }
        });

        if (ownedCategories.size === 0) {
            return { html: '<span style="color:#999; font-size:12px;">구독 가전 없음</span>' };
        }

        let bestMatch = null;
        let bestMissingCount = 999;

        for (const pkg of LIFESTYLE_PACKAGES) {
            const missing = pkg.required.filter(cat => !ownedCategories.has(cat));
            const missingCount = missing.length;
            
            if (missingCount < bestMissingCount) {
                bestMissingCount = missingCount;
                bestMatch = { pkg, missing };
            } else if (missingCount === bestMissingCount && bestMatch) {
                if (pkg.discVal > bestMatch.pkg.discVal) {
                    bestMatch = { pkg, missing };
                }
            }
        }

        if (!bestMatch) {
            return { html: '<span style="color:#999; font-size:12px;">해당 패키지 없음</span>' };
        }

        const { pkg, missing } = bestMatch;
        const rate = pkg.discVal || 0;
        
        if (missing.length === 0) {
            return { html: `<div class="lifestyle-badge ok">🎉 ${rate}% 추가 할인 달성!</div>` };
        } else if (missing.length === 1) {
            return { html: `<div class="lifestyle-badge near">💡 ${rate}% 할인 1개 임박!</div><div class="lifestyle-tip">(${missing[0]} 추가 시)</div>` };
        } else {
            const missingText = missing.length > 2 ? `${missing[0]} 외 ${missing.length - 1}개` : missing.join(', ');
            return { html: `<div class="lifestyle-badge coral">🎁 ${rate}% 추가 할인 기회</div><div class="lifestyle-tip">(${missingText} 추가 시)</div>` };
        }
    } catch(e) {
        return { html: `<span style="color:red; font-size:12px;">오류: ${e.message}</span>` };
    }
}

